const name = msg.payload.name;
const isInside = msg.payload.location === 'inside';

// % SoC change per 60s poll
const CHARGE_RATE = 0.5;   // full charge in ~3.3 h at home
const DRAIN_RATE  = 0.2;   // flat after ~8 h outside

const key = 'soc_' + name;
let soc = flow.get(key);
if (soc === undefined) soc = 50;

soc = isInside
    ? Math.min(100, soc + CHARGE_RATE)
    : Math.max(0,   soc - DRAIN_RATE);

flow.set(key, soc);

const rounded = parseFloat(soc.toFixed(1));
const chargingState = !isInside ? 0 : rounded >= 100 ? 3 : 2;
// 0=Disconnected  2=Charging  3=Charged

msg.payload = {
    AtSite:        isInside ? 1 : 0,
    Soc:           rounded,
    ChargingState: chargingState,
    'Ac/Power':    isInside ? 2300 : 0,
    RangeToGo:     Math.round(rounded * 3)
};
msg.catName = name;
return msg;
